import express from "express";
import path from "path";
import dotenv from "dotenv";
import { createServer as createViteServer } from "vite";

// Load environment variables
dotenv.config();

const app = express();
const PORT = 3000;

app.use(express.json({ limit: "15mb" }));

// Dummy/fallback API routes to prevent client crashes if any old references persist
app.post("/api/parse-task", (req, res) => {
  const textToParse = req.body.text || "";
  const priority = textToParse.includes("بالا") || textToParse.includes("فوری") ? "high" : "medium";
  let category = "کارهای شخصی";
  if (textToParse.includes("بیمه") || textToParse.includes("مالی") || textToParse.includes("بانک")) category = "مالی و اقتصادی";
  if (textToParse.includes("پروژه") || textToParse.includes("جلسه") || textToParse.includes("کار")) category = "امور کاری / شغلی";
  if (textToParse.includes("ورزش") || textToParse.includes("دویدن") || textToParse.includes("سلامتی")) category = "سلامتی و ورزش";

  const calculatedDate = textToParse.includes("فردا") 
    ? new Date(Date.now() + 86400000).toISOString().split("T")[0]
    : (req.body.currentDate || new Date().toISOString().split("T")[0]);

  res.json({
    title: textToParse.replace(/فردا|امروز|بعد از ظهر|صبح|ساعت/g, "").trim() || textToParse,
    description: "تحلیل محلی (آفلاین)",
    priority: priority,
    category: category,
    dueDate: calculatedDate,
    timeOfDay: textToParse.includes("صبح") ? "morning" : textToParse.includes("عصر") || textToParse.includes("ظهر") ? "afternoon" : "anytime"
  });
});

app.post("/api/transcribe-voice", (req, res) => {
  res.json({ transcription: "سیستم صوتی به علت محلی‌سازی کلا غیرفعال است." });
});

app.post("/api/analyze-productivity", (req, res) => {
  res.json({ text: "این قابلیت غیرفعال شده است." });
});

app.get("/api/health", (req, res) => {
  res.json({ status: "ok", time: new Date() });
});

// Vite Setup
const startServer = async () => {
  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), "dist");
    app.use(express.static(distPath));
    app.get("*", (req, res) => {
      res.sendFile(path.join(distPath, "index.html"));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`Liferz local server running on port ${PORT}`);
  });
};

startServer();
